{
  "name": "GlowTrack - AI Beauty Device Hub",
  "description": "A sophisticated low-fidelity prototype for a professional beauty device management WeChat mini-program, featuring AI skin analysis, remote device control, and personalized treatment scheduling.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum DeviceMode {
  CLEAN = 'CLEAN',
  EMS = 'EMS',
  RF = 'RF',
  COOL = 'COOL'
}

export interface SkinReport {
  score: number;
  hydration: number;
  elasticity: number;
  oiliness: number;
  advice: string;
}

export interface UserProfile {
  name: string;
  skinType: string;
  streakCount: number;
}

import React, { useState } from 'react';
import { HashRouter as Router, Routes, Route, Link, useLocation } from 'react-router-dom';
import Dashboard from './pages/Dashboard';
import DeviceControl from './pages/DeviceControl';
import SkinAnalysis from './pages/SkinAnalysis';
import Profile from './pages/Profile';

// Icons using Lucide-style simple SVG components
const NavIcon = ({ name, active }: { name: string; active: boolean }) => {
  const color = active ? '#3b82f6' : '#94a3b8';
  switch (name) {
    case 'home':
      return <svg className="w-6 h-6" fill="none" stroke={color} viewBox="0 0 24 24" strokeWidth="2"><path d="M3 9l9-7 9 7v11a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z"/><polyline points="9 22 9 12 15 12 15 22"/></svg>;
    case 'device':
      return <svg className="w-6 h-6" fill="none" stroke={color} viewBox="0 0 24 24" strokeWidth="2"><path d="M12 2v20M17 5H7a2 2 0 0 0-2 2v10a2 2 0 0 0 2 2h10a2 2 0 0 0 2-2V7a2 2 0 0 0-2-2z"/></svg>;
    case 'analysis':
      return <svg className="w-6 h-6" fill="none" stroke={color} viewBox="0 0 24 24" strokeWidth="2"><path d="M22 12h-4l-3 9L9 3l-3 9H2"/></svg>;
    case 'profile':
      return <svg className="w-6 h-6" fill="none" stroke={color} viewBox="0 0 24 24" strokeWidth="2"><path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"/><circle cx="12" cy="7" r="4"/></svg>;
    default:
      return null;
  }
};

const TabBar = () => {
  const location = useLocation();
  const tabs = [
    { path: '/', name: '首页', icon: 'home' },
    { path: '/analysis', name: '测肤', icon: 'analysis' },
    { path: '/device', name: '仪器', icon: 'device' },
    { path: '/profile', name: '我的', icon: 'profile' },
  ];

  return (
    <div className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-100 px-6 py-3 flex justify-between items-center z-50">
      {tabs.map((tab) => (
        <Link key={tab.path} to={tab.path} className="flex flex-col items-center gap-1">
          <NavIcon name={tab.icon} active={location.pathname === tab.path} />
          <span className={`text-[10px] font-medium ${location.pathname === tab.path ? 'text-blue-500' : 'text-gray-400'}`}>
            {tab.name}
          </span>
        </Link>
      ))}
    </div>
  );
};

const App: React.FC = () => {
  return (
    <Router>
      <div className="max-w-md mx-auto min-h-screen bg-slate-50 relative pb-24 no-scrollbar">
        {/* Header Mockup */}
        <header className="sticky top-0 bg-white/80 backdrop-blur-md px-6 py-4 flex justify-between items-center border-b border-gray-100 z-40">
          <h1 className="text-xl font-bold text-gray-800">GlowTrack</h1>
          <div className="flex gap-2">
            <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse" title="Device Connected"></div>
            <div className="w-4 h-4 rounded-sm border border-gray-300"></div>
          </div>
        </header>

        <main className="p-4">
          <Routes>
            <Route path="/" element={<Dashboard />} />
            <Route path="/device" element={<DeviceControl />} />
            <Route path="/analysis" element={<SkinAnalysis />} />
            <Route path="/profile" element={<Profile />} />
          </Routes>
        </main>

        <TabBar />
      </div>
    </Router>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getSkinAdvice = async (metrics: { hydration: number; elasticity: number; oiliness: number }) => {
  const prompt = `Based on these skin metrics (Hydration: ${metrics.hydration}%, Elasticity: ${metrics.elasticity}%, Oiliness: ${metrics.oiliness}%), provide a short, professional beauty advice (max 50 words) in Chinese for a beauty device user.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: "You are a professional skincare expert and beauty device consultant. Answer in Chinese.",
        temperature: 0.7,
      }
    });
    return response.text || "保持补水，建议配合EMS微电流模式提升弹性。";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "您的肤质正在改善，建议继续坚持日常护理。";
  }
};

export const generatePlan = async (skinType: string) => {
    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: `为${skinType}肤质制定一个简单的3步美容仪使用方案。`,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            step: { type: Type.STRING },
                            mode: { type: Type.STRING },
                            duration: { type: Type.STRING }
                        },
                        required: ["step", "mode", "duration"]
                    }
                }
            }
        });
        return JSON.parse(response.text);
    } catch (e) {
        return [
            { step: "深层清洁", mode: "CLEAN", duration: "3 min" },
            { step: "紧致提升", mode: "EMS", duration: "5 min" },
            { step: "锁水保湿", mode: "RF", duration: "2 min" }
        ];
    }
}

import React, { useState, useEffect } from 'react';
import { DeviceMode } from '../types';

const DeviceControl: React.FC = () => {
  const [activeMode, setActiveMode] = useState<DeviceMode>(DeviceMode.EMS);
  const [intensity, setIntensity] = useState(3);
  const [timeLeft, setTimeLeft] = useState(600); // 10 minutes in seconds
  const [isActive, setIsActive] = useState(false);

  useEffect(() => {
    let interval: any = null;
    if (isActive && timeLeft > 0) {
      interval = setInterval(() => {
        setTimeLeft((prev) => prev - 1);
      }, 1000);
    } else if (timeLeft === 0) {
      setIsActive(false);
      clearInterval(interval);
    }
    return () => clearInterval(interval);
  }, [isActive, timeLeft]);

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs < 10 ? '0' : ''}${secs}`;
  };

  const modes = [
    { id: DeviceMode.CLEAN, name: '深度清洁', icon: '✨' },
    { id: DeviceMode.EMS, name: '微电流提拉', icon: '⚡' },
    { id: DeviceMode.RF, name: '射频嫩肤', icon: '🔥' },
    { id: DeviceMode.COOL, name: '冰敷收敛', icon: '❄️' },
  ];

  return (
    <div className="flex flex-col gap-6 animate-in slide-in-from-bottom-4 duration-500 pb-10">
      {/* Device Visual Mockup */}
      <div className="bg-white rounded-[40px] p-8 shadow-inner border border-gray-100 flex flex-col items-center gap-6">
        <div className="w-16 h-32 bg-gray-100 rounded-full relative flex flex-col items-center justify-center border-4 border-gray-50">
             <div className="w-8 h-8 rounded-full bg-blue-500/20 absolute top-4 animate-ping"></div>
             <div className="w-10 h-10 rounded-full bg-white shadow-sm border border-gray-100 z-10 flex items-center justify-center text-lg">
                {modes.find(m => m.id === activeMode)?.icon}
             </div>
        </div>
        <div className="text-center">
            <p className="text-3xl font-mono font-bold tracking-widest text-gray-800">{formatTime(timeLeft)}</p>
            <p className="text-xs text-gray-400 mt-1 uppercase tracking-widest">Remaining Time</p>
        </div>
      </div>

      {/* Mode Selector */}
      <div className="grid grid-cols-2 gap-3">
        {modes.map((mode) => (
          <button
            key={mode.id}
            onClick={() => setActiveMode(mode.id)}
            className={`p-4 rounded-2xl border transition-all flex flex-col items-start gap-2 ${
              activeMode === mode.id
                ? 'bg-blue-500 border-blue-500 text-white shadow-lg shadow-blue-200'
                : 'bg-white border-gray-100 text-gray-600 hover:border-blue-200'
            }`}
          >
            <span className="text-xl">{mode.icon}</span>
            <span className="text-xs font-bold">{mode.name}</span>
          </button>
        ))}
      </div>

      {/* Intensity Control */}
      <div className="bg-white p-6 rounded-3xl border border-gray-100 space-y-4">
        <div className="flex justify-between items-center">
            <h4 className="text-sm font-bold text-gray-800">强度调节</h4>
            <span className="text-blue-500 font-bold">Level {intensity}</span>
        </div>
        <input 
            type="range" 
            min="1" 
            max="5" 
            value={intensity} 
            onChange={(e) => setIntensity(parseInt(e.target.value))}
            className="w-full h-2 bg-gray-100 rounded-lg appearance-none cursor-pointer accent-blue-500"
        />
        <div className="flex justify-between text-[10px] text-gray-300 font-bold px-1">
            <span>LOW</span>
            <span>HIGH</span>
        </div>
      </div>

      {/* Control Action */}
      <button 
        onClick={() => setIsActive(!isActive)}
        className={`w-full py-4 rounded-2xl font-bold text-lg transition-all shadow-lg active:scale-95 ${
            isActive 
            ? 'bg-red-50 text-red-500 border border-red-100' 
            : 'bg-blue-600 text-white shadow-blue-200'
        }`}
      >
        {isActive ? '停止运行' : '开始护理'}
      </button>
    </div>
  );
};

export default DeviceControl;

import React, { useState } from 'react';
import { getSkinAdvice } from '../services/geminiService';

const SkinAnalysis: React.FC = () => {
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [report, setReport] = useState<{
    hydration: number;
    elasticity: number;
    oiliness: number;
    advice: string;
  } | null>(null);

  const handleStartAnalysis = async () => {
    setIsAnalyzing(true);

    // Simulate camera delay and calculation
    setTimeout(async () => {
        const metrics = {
            hydration: Math.floor(Math.random() * 40) + 40,
            elasticity: Math.floor(Math.random() * 30) + 60,
            oiliness: Math.floor(Math.random() * 20) + 10,
        };

        const advice = await getSkinAdvice(metrics);

        setReport({ ...metrics, advice });
        setIsAnalyzing(false);
    }, 2500);
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-700">
      {!report && !isAnalyzing && (
        <div className="flex flex-col items-center justify-center py-12 gap-8">
          <div className="w-56 h-56 rounded-full border-2 border-dashed border-blue-200 flex items-center justify-center relative">
            <div className="w-48 h-48 rounded-full bg-slate-100 flex items-center justify-center">
                 <svg className="w-16 h-16 text-slate-300" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1" d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z"/>
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1" d="M15 13a3 3 0 11-6 0 3 3 0 016 0z"/>
                 </svg>
            </div>
            <div className="absolute inset-0 border-2 border-blue-500 rounded-full animate-[spin_10s_linear_infinite] border-t-transparent border-l-transparent"></div>
          </div>
          <div className="text-center space-y-2">
            <h2 className="text-xl font-bold text-gray-800">智能 AI 测肤</h2>
            <p className="text-gray-400 text-sm max-w-[240px]">利用前置摄像头分析您的面部细节，为您定制专属护肤方案</p>
          </div>
          <button 
            onClick={handleStartAnalysis}
            className="bg-blue-600 text-white px-8 py-3 rounded-full font-bold shadow-xl shadow-blue-200 active:scale-95 transition-all"
          >
            开始扫描
          </button>
        </div>
      )}

      {isAnalyzing && (
        <div className="flex flex-col items-center justify-center py-20 gap-6">
          <div className="relative w-48 h-48 bg-gray-100 rounded-3xl overflow-hidden">
             <img src="https://picsum.photos/seed/face/400/400" className="w-full h-full object-cover opacity-60 grayscale" alt="Scanning face" />
             <div className="absolute top-0 left-0 w-full h-1 bg-blue-500 shadow-[0_0_15px_rgba(59,130,246,0.8)] animate-[scan_2s_ease-in-out_infinite]"></div>
          </div>
          <p className="text-blue-500 font-medium animate-pulse">AI 正在精准分析中...</p>
          <style>{`
            @keyframes scan {
              0%, 100% { transform: translateY(0); }
              50% { transform: translateY(192px); }
            }
          `}</style>
        </div>
      )}

      {report && (
        <div className="space-y-6 animate-in slide-in-from-top-4 duration-500">
           <div className="bg-white rounded-3xl p-6 shadow-sm border border-gray-100">
                <h3 className="text-center text-sm font-bold text-gray-400 mb-6 tracking-widest uppercase">测肤报告报告</h3>

                <div className="grid grid-cols-3 gap-4 mb-8">
                    {[
                        { label: '水润', val: report.hydration, color: 'text-cyan-500' },
                        { label: '弹性', val: report.elasticity, color: 'text-purple-500' },
                        { label: '含油', val: report.oiliness, color: 'text-amber-500' }
                    ].map(stat => (
                        <div key={stat.label} className="text-center">
                            <div className={`text-2xl font-bold ${stat.color}`}>{stat.val}%</div>
                            <div className="text-[10px] text-gray-400 font-bold uppercase">{stat.label}</div>
                        </div>
                    ))}
                </div>

                <div className="bg-blue-50/50 rounded-2xl p-4 border border-blue-100">
                    <div className="flex gap-2 items-center mb-2">
                        <span className="text-blue-500">
                            <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2L2 7l10 5 10-5-10-5zM2 17l10 5 10-5M2 12l10 5 10-5"/></svg>
                        </span>
                        <span className="text-xs font-bold text-blue-700">专家建议</span>
                    </div>
                    <p className="text-sm text-gray-700 leading-relaxed italic">
                        "{report.advice}"
                    </p>
                </div>
           </div>

           <div className="flex gap-3">
                <button onClick={() => setReport(null)} className="flex-1 py-4 border border-gray-200 rounded-2xl text-gray-500 font-bold text-sm bg-white">
                    重新测试
                </button>
                <button className="flex-2 flex-[2] py-4 bg-slate-900 text-white rounded-2xl font-bold text-sm shadow-lg">
                    查看完整建议
                </button>
           </div>
        </div>
      )}
    </div>
  );
};

export default SkinAnalysis;

import React from 'react';
import { HashRouter as Router, Routes, Route, Link, useLocation } from 'react-router-dom';
