const DeviceControl: React.FC = () => {
  const [activeMode, setActiveMode] = useState<DeviceMode>(DeviceMode.FACE);
  const [gear, setGear] = useState(1);
  const [isPowerOn, setIsPowerOn] = useState(false);
  const [isFiring, setIsFiring] = useState(false);
  const [epActive, setEpActive] = useState(false);
  const [emsActive, setEmsActive] = useState(false);
  const [usageTime, setUsageTime] = useState(0); // Seconds

  useEffect(() => {
    let interval: any = null;
    if (isPowerOn && isFiring) {
      interval = setInterval(() => {
        setUsageTime((prev) => prev + 1);
      }, 1000);
    } else {
      clearInterval(interval);
    }
    return () => clearInterval(interval);
  }, [isPowerOn, isFiring]);

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs < 10 ? '0' : ''}${secs}`;
  };

  const modes = [
    { id: DeviceMode.FACE, name: '脸部模式', icon: '👤' },
    { id: DeviceMode.EYE, name: '眼周模式', icon: '👁️' },
    { id: DeviceMode.INFUSION, name: '导入模式', icon: '💧' },
    { id: DeviceMode.LIFTING, name: '提拉模式', icon: '✨' },
  ];

  const togglePower = () => {
    if (isPowerOn) {
      setIsFiring(false);
      setEpActive(false);
      setEmsActive(false);
    }
    setIsPowerOn(!isPowerOn);
  };

  return (
    <div className="px-6 py-4 space-y-8 animate-in slide-in-from-bottom-4 duration-500 pb-20">
      {/* Device Status Display */}
      <div className={`relative bg-white rounded-[48px] p-10 shadow-sm border border-[#F5EBE0] transition-all duration-700 ${!isPowerOn ? 'opacity-60 grayscale' : ''}`}>
