    case 'profile':
      return <svg className="w-6 h-6" fill={active ? color : "none"} stroke={color} viewBox="0 0 24 24" strokeWidth="1.5"><path d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z"/></svg>;
