import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { getSkinAdvice } from '../services/geminiService';

const SkinAnalysis: React.FC = () => {
  const navigate = useNavigate();
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [report, setReport] = useState<{
    hydration: number;
    elasticity: number;
    oiliness: number;
    advice: string;
  } | null>(null);

  const handleStartAnalysis = async () => {
    setIsAnalyzing(true);
    setTimeout(async () => {
        const metrics = {
            hydration: Math.floor(Math.random() * 40) + 40,
            elasticity: Math.floor(Math.random() * 30) + 60,
            oiliness: Math.floor(Math.random() * 20) + 10,
        };
        const advice = await getSkinAdvice(metrics);
        const finalReport = { ...metrics, advice, date: new Date().toLocaleString(), score: Math.floor(Math.random() * 20) + 75 };

        // Save to archive
        const archive = JSON.parse(localStorage.getItem('skinArchive') || '[]');
        localStorage.setItem('skinArchive', JSON.stringify([finalReport, ...archive]));
        // Set current for plan
        localStorage.setItem('latestSkinReport', JSON.stringify(finalReport));

        setReport(finalReport);
        setIsAnalyzing(false);
    }, 2500);
  };

  return (
    <div className="px-6 py-4 space-y-6 animate-in fade-in duration-700">
      {!report && !isAnalyzing && (
        <div className="flex flex-col items-center justify-center py-12 gap-10">
          <div className="relative">
            <div className="w-64 h-64 rounded-full border-2 border-dashed border-[#D7C4B2] flex items-center justify-center">
                <div className="w-56 h-56 rounded-full bg-white shadow-xl flex items-center justify-center border border-[#F5EBE0]">
                     <svg className="w-20 h-20 text-[#D7C4B2] opacity-50" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1" d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z"/>
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1" d="M15 13a3 3 0 11-6 0 3 3 0 016 0z"/>
                     </svg>
