import { useParams, useNavigate } from 'react-router-dom';
import { OrderStatus, Address } from '../types';

const ProductDetail: React.FC = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [isPurchasing, setIsPurchasing] = useState(false);
  const [selectedAddress, setSelectedAddress] = useState<Address | null>(null);

  useEffect(() => {
    const addresses = JSON.parse(localStorage.getItem('addresses') || '[]');
    const defaultAddr = addresses.find((a: Address) => a.isDefault) || addresses[0];
    if (defaultAddr) setSelectedAddress(defaultAddr);
  }, []);

  const product = {
    id: id,
    name: id === '1' ? 'SHEEN Pro V2' : 'SHEEN Premium Device',
    price: id === '1' ? 2980 : 3500,
    img: 'https://images.unsplash.com/photo-1590156221122-c446210140aa?auto=format&fit=crop&q=80&w=800',
    description: '采用最新RF射频技术，深层激活胶原蛋白，紧致下颌线。专为亚洲肤质定制。',
    specs: ['IPX7防水', '超长待机30天', '3级可调节强度', '智能温控保护']
  };

  const handleBuy = () => {
    if (!selectedAddress) {
      alert('请先添加收货地址');
      navigate('/address');
      return;
    }

    setIsPurchasing(true);
    setTimeout(() => {
      const newOrder = {
        id: 'ORD-' + Math.random().toString(36).substr(2, 9).toUpperCase(),
        productId: product.id,
        productName: product.name,
        productImage: product.img,
        price: product.price,
        status: OrderStatus.PROCESSING,
        orderTime: new Date().toLocaleString(),
        trackingNumber: 'SF1234567890',
        address: selectedAddress
      };

      const orders = JSON.parse(localStorage.getItem('orders') || '[]');
      localStorage.setItem('orders', JSON.stringify([newOrder, ...orders]));

      alert('支付成功！');
      navigate('/orders');
    }, 1500);
  };

  return (
    <div className="min-h-screen bg-white animate-in slide-in-from-bottom-10 duration-500 pb-24 relative z-0">
      <div className="relative h-[450px] bg-[#FAF7F2]">
        <button 
          type="button"
          onClick={() => navigate(-1)}
          className="absolute top-8 left-6 z-50 w-10 h-10 rounded-full bg-white/90 backdrop-blur-md flex items-center justify-center text-[#4A3E3E] shadow-lg active:scale-90 transition-all cursor-pointer"
          aria-label="返回"
        >
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M15 19l-7-7 7-7"/></svg>
        </button>
        <img src={product.img} className="w-full h-full object-cover" alt={product.name} />
      </div>

      <div className="px-8 -mt-10 relative bg-white rounded-t-[48px] pt-10 space-y-8 z-10">
        <div className="space-y-4">
          <div className="flex justify-between items-start">
            <h1 className="text-3xl font-serif text-[#4A3E3E]">{product.name}</h1>
            <div className="text-2xl font-bold text-[#D7C4B2]">¥{product.price}</div>
          </div>
          <p className="text-[#8B7E74] leading-relaxed text-sm">{product.description}</p>
        </div>

        {/* Address Selection */}
        <div className="space-y-4">
          <div className="flex justify-between items-center">
            <h4 className="text-xs font-bold text-[#C0B3A5] uppercase tracking-widest">收货地址</h4>
            <button onClick={() => navigate('/address')} className="text-[10px] text-[#D7C4B2] font-bold">更换地址</button>
          </div>
          <div className="bg-[#FAF7F2] p-5 rounded-3xl border border-[#F5EBE0]/50 flex items-center justify-between">
            {selectedAddress ? (
              <div className="space-y-1">
                <p className="text-sm font-bold text-[#4A3E3E]">{selectedAddress.name} <span className="ml-2 font-normal text-[#8B7E74]">{selectedAddress.phone}</span></p>
                <p className="text-[10px] text-[#8B7E74]">{selectedAddress.region} {selectedAddress.detail}</p>
              </div>
            ) : (
              <p className="text-xs text-[#C0B3A5]">尚未添加收货地址</p>
            )}
            <svg className="w-4 h-4 text-[#F5EBE0]" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M9 5l7 7-7 7"/></svg>
          </div>
        </div>

        <div className="space-y-4">
          <h4 className="text-xs font-bold text-[#C0B3A5] uppercase tracking-widest">产品规格</h4>
          <div className="grid grid-cols-2 gap-3">
            {product.specs.map((s, i) => (
