            <span className="text-[10px] text-[#C0B3A5] font-bold uppercase tracking-widest">Total Price</span>
            <span className="text-xl font-bold text-[#D7C4B2]">¥{product.price}</span>
        </div>
        <button 
          onClick={handleBuy}
          disabled={isPurchasing}
          className="flex-[2] bg-[#4A3E3E] text-white py-4 rounded-2xl font-bold text-sm tracking-widest shadow-xl active:scale-95 disabled:opacity-50 transition-all flex items-center justify-center gap-2"
