              : 'bg-[#4A3E3E] text-white shadow-gray-200'
            }`}
          >
            {isFiring ? '正在发射' : '长按发射'}
          </button>
        </div>

        <div className="text-center pt-4">
            <p className="text-[10px] text-[#C0B3A5] font-bold uppercase tracking-[0.4em]">Advanced Skin Technology</p>
        </div>
      </div>
    </div>
  );
};

