import React, { useState, useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { DeviceMode } from '../types';

const DeviceControl: React.FC = () => {
  const navigate = useNavigate();
  const [activeMode, setActiveMode] = useState<DeviceMode>(DeviceMode.FACE);
  const [gear, setGear] = useState(1);
  const [isPowerOn, setIsPowerOn] = useState(false);

  // Auto mode state (replaces isFiring for continuous operations)
  const [autoMode, setAutoMode] = useState(false);

  // Specific timing states
  const [shotsRemaining, setShotsRemaining] = useState(600);
  const [timerRemaining, setTimerRemaining] = useState(300); // 5 minutes in seconds

  const longPressTimer = useRef<any>(null);
  const isLongPress = useRef(false);

  // Reset state when mode changes
  useEffect(() => {
    setShotsRemaining(600);
    setTimerRemaining(300);
    setAutoMode(false);
  }, [activeMode]);

  // Handle Auto Mode Logic (Timer countdown or Shot decrement)
  useEffect(() => {
    let interval: any = null;
    const isShotMode = activeMode === DeviceMode.FACE || activeMode === DeviceMode.EYE;
    const isTimerMode = activeMode === DeviceMode.INFUSION || activeMode === DeviceMode.LIFTING;

    if (isPowerOn && autoMode) {
      if (isShotMode && shotsRemaining > 0) {
        // Auto shots: 2 per second
        interval = setInterval(() => {
          setShotsRemaining(prev => {
            if (prev <= 1) {
              setAutoMode(false);
              return 0;
            }
            return prev - 1;
          });
        }, 500);
      } else if (isTimerMode && timerRemaining > 0) {
        // Timer countdown
        interval = setInterval(() => {
          setTimerRemaining((prev) => {
            if (prev <= 1) {
              setAutoMode(false);
              return 0;
            }
            return prev - 1;
          });
        }, 1000);
      } else if ((isShotMode && shotsRemaining === 0) || (isTimerMode && timerRemaining === 0)) {
        setAutoMode(false);
      }
    } else {
        // If power off, stop auto
        if (!isPowerOn) setAutoMode(false);
    }

    return () => clearInterval(interval);
  }, [isPowerOn, autoMode, activeMode, shotsRemaining, timerRemaining]);

  const handlePressStart = () => {
    if (!isPowerOn) return;
    const isShotMode = activeMode === DeviceMode.FACE || activeMode === DeviceMode.EYE;

    if (isShotMode) {
      if (autoMode) return; // Already in auto, waiting for release/click to stop

      isLongPress.current = false;
      longPressTimer.current = setTimeout(() => {
        isLongPress.current = true;
        setAutoMode(true);
      }, 1000); // 1s long press to trigger auto
    }
  };

  const handlePressEnd = () => {
    if (!isPowerOn) return;
    const isShotMode = activeMode === DeviceMode.FACE || activeMode === DeviceMode.EYE;
    const isTimerMode = activeMode === DeviceMode.INFUSION || activeMode === DeviceMode.LIFTING;

    if (isShotMode) {
      if (longPressTimer.current) {
        clearTimeout(longPressTimer.current);
        longPressTimer.current = null;
      }

      if (autoMode) {
        // If in auto mode
        if (!isLongPress.current) {
           // Short press (click) while in auto -> Stop
           setAutoMode(false);
        }
        // If isLongPress was true, we just entered auto, so stay in auto
      } else {
        // Not in auto, check if it was a short press
        if (!isLongPress.current) {
          setShotsRemaining(prev => Math.max(0, prev - 1));
        }
      }
      isLongPress.current = false;
    } else if (isTimerMode) {
      // Toggle start/stop for timer modes
      setAutoMode(!autoMode);
    }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs < 10 ? '0' : ''}${secs}`;
  };

  const modes = [
    { id: DeviceMode.FACE, name: '脸部模式', icon: '👤', type: 'shots' },
    { id: DeviceMode.EYE, name: '眼周模式', icon: '👁️', type: 'shots' },
    { id: DeviceMode.INFUSION, name: '导入模式', icon: '💧', type: 'timer' },
    { id: DeviceMode.LIFTING, name: '提拉模式', icon: '✨', type: 'timer' },
  ];

  const currentModeInfo = modes.find(m => m.id === activeMode);

  const togglePower = () => {
    if (isPowerOn) {
      setAutoMode(false);
    }
    setIsPowerOn(!isPowerOn);
  };

  // Determine active technologies based on mode
  const isHifuActive = isPowerOn && (activeMode === DeviceMode.FACE || activeMode === DeviceMode.EYE);
  const isEpActive = isPowerOn && (activeMode === DeviceMode.INFUSION);
  const isEmsActive = isPowerOn && (activeMode === DeviceMode.LIFTING);

  const getButtonText = () => {
    if (!isPowerOn) return '请先开机';
    const isShotMode = activeMode === DeviceMode.FACE || activeMode === DeviceMode.EYE;

    if (isShotMode) {
        return autoMode ? '自动发射中...' : '发射 (长按连发)';
    } else {
        return autoMode ? '暂停护理' : '开始护理';
    }
  };

  return (
    <div className="animate-in slide-in-from-bottom-4 duration-500 pb-20">
      {/* Sticky Header with Back Button */}
      <div className="bg-white px-6 pt-2 pb-4 shadow-sm sticky top-0 z-10 border-b border-[#F5EBE0]/50">
        <div className="flex items-center gap-4">
          <button onClick={() => navigate(-1)} className="text-[#4A3E3E] p-1 active:scale-90 transition-transform">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 19l-7-7 7-7"/></svg>
          </button>
          <h2 className="text-xl font-serif text-[#4A3E3E]">设备控制</h2>
        </div>
      </div>

      <div className="px-6 py-6 space-y-8">
        {/* Device Status Display */}
        <div className={`relative bg-white rounded-[48px] p-10 shadow-sm border border-[#F5EBE0] transition-all duration-700 ${!isPowerOn ? 'opacity-60 grayscale' : ''}`}>
          <div className="absolute top-6 right-8">
              <div className={`w-3 h-3 rounded-full ${isPowerOn ? 'bg-[#D7C4B2] animate-pulse shadow-[0_0_10px_#D7C4B2]' : 'bg-gray-200'}`}></div>
          </div>

          <div className="flex flex-col items-center gap-6">
              <div className="text-center space-y-1">
                  <p className="text-[10px] text-[#C0B3A5] font-bold uppercase tracking-[0.3em]">
                    {currentModeInfo?.type === 'shots' ? 'Remaining Shots' : 'Remaining Time'}
                  </p>
                  <h3 className="text-5xl font-serif text-[#4A3E3E] tabular-nums">
                    {currentModeInfo?.type === 'shots' ? shotsRemaining : formatTime(timerRemaining)}
                  </h3>
                  {currentModeInfo?.type === 'shots' && (
                    <span className="text-[10px] text-[#D7C4B2] font-bold uppercase tracking-widest">发</span>
                  )}
              </div>

              {/* Technology Indicators */}
              <div className="flex gap-8 items-center pt-2">
                  <div className="flex flex-col items-center gap-1">
                      <span className={`text-[10px] font-bold uppercase tracking-widest ${isHifuActive ? 'text-[#D7C4B2]' : 'text-gray-300'}`}>HIFU</span>
                      <div className={`w-1.5 h-1.5 rounded-full transition-colors ${isHifuActive ? 'bg-[#D7C4B2]' : 'bg-transparent'}`}></div>
                  </div>
                  <div className="w-[1px] h-6 bg-[#F5EBE0]"></div>
                  <div className="flex flex-col items-center gap-1">
                      <span className={`text-[10px] font-bold uppercase tracking-widest ${isEpActive ? 'text-[#D7C4B2]' : 'text-gray-300'}`}>EP</span>
                      <div className={`w-1.5 h-1.5 rounded-full transition-colors ${isEpActive ? 'bg-[#D7C4B2]' : 'bg-transparent'}`}></div>
                  </div>
                  <div className="w-[1px] h-6 bg-[#F5EBE0]"></div>
                  <div className="flex flex-col items-center gap-1">
                      <span className={`text-[10px] font-bold uppercase tracking-widest ${isEmsActive ? 'text-[#D7C4B2]' : 'text-gray-300'}`}>EMS</span>
                      <div className={`w-1.5 h-1.5 rounded-full transition-colors ${isEmsActive ? 'bg-[#D7C4B2]' : 'bg-transparent'}`}></div>
                  </div>
              </div>
          </div>
        </div>

        {/* Mode Grid */}
        <div className="grid grid-cols-2 gap-4">
          {modes.map((m) => (
            <button
              key={m.id}
              disabled={!isPowerOn}
              onClick={() => setActiveMode(m.id)}
              className={`p-5 rounded-[32px] border transition-all flex flex-col items-center gap-2 group ${
                activeMode === m.id && isPowerOn
                  ? 'bg-[#D7C4B2] border-[#D7C4B2] text-white shadow-lg'
                  : 'bg-white border-[#F5EBE0] text-[#8B7E74] disabled:opacity-40'
              }`}
            >
              <span className="text-2xl group-active:scale-125 transition-transform">{m.icon}</span>
              <span className="text-xs font-bold tracking-wider">{m.name}</span>
            </button>
          ))}
        </div>

        {/* Gears Control */}
        <div className={`bg-white p-8 rounded-[40px] border border-[#F5EBE0] space-y-6 transition-opacity ${!isPowerOn ? 'opacity-40 pointer-events-none' : ''}`}>
          <div className="flex justify-between items-center px-2">
              <h4 className="text-sm font-bold text-[#4A3E3E] tracking-widest">档位强度</h4>
              <span className="text-lg font-serif text-[#D7C4B2]">{gear}档</span>
          </div>
          <div className="flex items-center justify-between gap-4 px-2">
              {[1, 2, 3, 4].map(g => (
                  <button
                      key={g}
                      onClick={() => setGear(g)}
                      className={`flex-1 h-12 rounded-2xl font-bold transition-all ${
                          gear === g 
                          ? 'bg-[#D7C4B2] text-white shadow-md' 
                          : 'bg-[#FAF7F2] text-[#C0B3A5] border border-[#F5EBE0]'
                      }`}
                  >
                      {g}
                  </button>
              ))}
          </div>
        </div>

        {/* Master Controls */}
        <div className="flex gap-4 items-stretch h-20">
          <button 
            onClick={togglePower}
            className={`w-24 rounded-[32px] font-bold transition-all shadow-xl active:scale-95 flex flex-col items-center justify-center gap-1 ${
              isPowerOn 
              ? 'bg-[#E5DACE] text-[#4A3E3E]' 
              : 'bg-[#4A3E3E] text-white'
            }`}
          >
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z"/></svg>
            <span className="text-[10px] tracking-widest">{isPowerOn ? '关机' : '开机'}</span>
          </button>

          <button 
            disabled={!isPowerOn || (currentModeInfo?.type === 'shots' ? shotsRemaining <= 0 : timerRemaining <= 0)}
            onMouseDown={handlePressStart}
            onMouseUp={handlePressEnd}
            onTouchStart={handlePressStart}
            onTouchEnd={handlePressEnd}
            onMouseLeave={handlePressEnd}
            className={`flex-1 rounded-[32px] font-bold text-lg transition-all shadow-xl active:scale-[0.98] disabled:opacity-40 relative overflow-hidden ${
              autoMode
              ? 'bg-gradient-to-r from-[#D7C4B2] to-[#C0B3A5] text-white shadow-[#D7C4B2]/40' 
              : 'bg-[#4A3E3E] text-white shadow-gray-300'
            }`}
          >
             {autoMode && (
                <div className="absolute inset-0 bg-white/20 animate-pulse"></div>
             )}
             <div className="relative z-10 flex flex-col items-center justify-center">
                <span>{getButtonText()}</span>
                {activeMode !== DeviceMode.INFUSION && activeMode !== DeviceMode.LIFTING && !autoMode && (
                     <div className="h-1 w-12 bg-white/20 mt-2 rounded-full"></div>
                )}
             </div>
          </button>
        </div>

        <div className="text-center pt-4">
            <p className="text-[10px] text-[#C0B3A5] font-bold uppercase tracking-[0.4em]">Advanced Skin Technology</p>
        </div>
      </div>
    </div>
  );
};

