const NavIcon = ({ name, active }: { name: string; active: boolean }) => {
  const color = active ? '#D7C4B2' : '#C0B3A5';
  switch (name) {
    case 'home':
      return <svg className="w-6 h-6" fill={active ? color : "none"} stroke={color} viewBox="0 0 24 24" strokeWidth="1.5"><path d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6"/></svg>;
    case 'new':
      return <svg className="w-6 h-6" fill={active ? color : "none"} stroke={color} viewBox="0 0 24 24" strokeWidth="1.5"><path d="M21 15.5V10a2 2 0 00-2-2h-3.5a2 2 0 01-1.414-.586L12 5.414a2 2 0 00-1.414-.586H7a2 2 0 00-2 2v10.5M5 15.5l1.5 1.5M21 15.5l-1.5 1.5m-14.5 0h14.5a1.5 1.5 0 001.5-1.5V15h-17.5v.5a1.5 1.5 0 001.5 1.5z"/></svg>;
    case 'analysis':
      return <div className={`w-12 h-12 rounded-full border-2 border-white shadow-md flex items-center justify-center -mt-6 transition-all ${active ? 'bg-[#D7C4B2] scale-110' : 'bg-white'}`}>
        <svg className={`w-6 h-6 ${active ? 'text-white' : 'text-[#D7C4B2]'}`} fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2"><path d="M12 4v1m6 11h2m-6 0h-2v4m0-11v3m0 0h.01M12 12h4.01M16 20h4M4 12h4m12 0h.01M5 8h2a1 1 0 001-1V5a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1zm12 0h2a1 1 0 001-1V5a1 1 0 00-1-1h-2a1 1 0 00-1 1v2a1 1 0 001 1zM5 20h2a1 1 0 001-1v-2a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1z"/></svg>
      </div>;
    case 'shop':
      return <svg className="w-6 h-6" fill={active ? color : "none"} stroke={color} viewBox="0 0 24 24" strokeWidth="1.5"><path d="M16 11V7a4 4 0 00-8 0v4M5 9h14l1 12H4L5 9z"/></svg>;
    case 'profile':
      return <svg className="w-6 h-6" fill={active ? color : "none"} stroke={color} viewBox="0 0 24 24" strokeWidth="1.5"><path d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z"/></svg>;
    default: return null;
  }
};

const Header = () => {
  const location = useLocation();
  const hidePaths = [
    '/product/', '/orders', '/address', '/activity/', '/activities',
    '/membership', '/auth', '/brand', '/feedback', '/edit-profile',
    '/skin-archive', '/care-plan', '/tutorial/', '/tutorials',
    '/full-history', '/care-logs', '/pairing', '/device', '/checkout'
  ];
  const shouldHide = hidePaths.some(p => location.pathname.startsWith(p));

  if (shouldHide) return null;

  return (
    <header className="px-6 py-4 flex justify-between items-center bg-[#FAF7F2] sticky top-0 z-40">
      <span className="text-xl font-medium tracking-tight text-[#4A3E3E] font-serif">SHEEN Me</span>
      <div className="flex items-center gap-2 bg-black/5 rounded-full px-3 py-1.5 backdrop-blur-sm">
        <div className="flex gap-1 items-center">
          <div className="w-1 h-1 rounded-full bg-[#4A3E3E]"></div>
          <div className="w-1 h-1 rounded-full bg-[#4A3E3E]"></div>
          <div className="w-1 h-1 rounded-full bg-[#4A3E3E]"></div>
        </div>
        <div className="w-[1px] h-3 bg-black/10 mx-1"></div>
        <div className="w-3.5 h-3.5 rounded-full border border-[#4A3E3E] flex items-center justify-center">
          <div className="w-1 h-1 rounded-full bg-[#4A3E3E]"></div>
        </div>
      </div>
    </header>
  );
};

const TabBar = () => {
  const location = useLocation();
  const tabs = [
    { path: '/', name: '首页', icon: 'home' },
    { path: '/new', name: '新品', icon: 'new' },
    { path: '/analysis', name: '测肤', icon: 'analysis' },
    { path: '/shop', name: '商城', icon: 'shop' },
    { path: '/profile', name: '我的', icon: 'profile' },
  ];

  const hideTabPaths = [
    '/product/', '/orders', '/address', '/activity/', '/activities',
    '/membership', '/auth', '/brand', '/feedback', '/edit-profile',
    '/skin-archive', '/care-plan', '/tutorial/', '/tutorials',
    '/full-history', '/care-logs', '/pairing', '/device', '/checkout'
  ];
  const shouldHide = hideTabPaths.some(p => location.pathname.startsWith(p));

  if (shouldHide) return null;

  return (
    <div className="fixed bottom-0 left-0 right-0 bg-white/95 backdrop-blur-xl border-t border-[#F5EBE0] px-4 py-3 flex justify-between items-center z-50 rounded-t-[32px] shadow-[0_-8px_30px_rgba(0,0,0,0.04)]">
      {tabs.map((tab) => (
        <Link key={tab.path} to={tab.path} className="flex flex-col items-center flex-1">
          <NavIcon name={tab.icon} active={location.pathname === tab.path} />
          {tab.icon !== 'analysis' && (
            <span className={`text-[10px] mt-1 font-bold tracking-wider ${location.pathname === tab.path ? 'text-[#D7C4B2]' : 'text-[#C0B3A5]'}`}>
              {tab.name}
            </span>
          )}
        </Link>
      ))}
    </div>
  );
};

const App: React.FC = () => {
  const [isPaired, setIsPaired] = useState(() => localStorage.getItem('paired') === 'true');

  useEffect(() => {
    const handlePairedChange = () => {
      setIsPaired(localStorage.getItem('paired') === 'true');
    };
    window.addEventListener('storage', handlePairedChange);
    return () => window.removeEventListener('storage', handlePairedChange);
  }, []);

  return (
    <Router>
      <div className="max-w-md mx-auto min-h-screen bg-[#FAF7F2] relative pb-28 no-scrollbar selection:bg-[#D7C4B2]/30">
        <Header />

        <main>
          <Routes>
            <Route path="/" element={<Dashboard paired={isPaired} />} />
            <Route path="/device" element={<DeviceControl />} />
            <Route path="/new" element={<NewProducts />} />
            <Route path="/shop" element={<Shop />} />
            <Route path="/product/:id" element={<ProductDetail />} />
            <Route path="/checkout/:id" element={<Checkout />} />
            <Route path="/orders" element={<OrderManagement />} />
            <Route path="/address" element={<AddressManagement />} />
            <Route path="/activities" element={<ActivityCenter />} />
            <Route path="/activity/:id" element={<ActivityDetail />} />
            <Route path="/membership" element={<MembershipBenefits />} />
            <Route path="/auth" element={<ProductAuthentication />} />
            <Route path="/brand" element={<BrandInfo />} />
            <Route path="/feedback" element={<Feedback />} />
            <Route path="/analysis" element={<SkinAnalysis />} />
            <Route path="/care-plan" element={<CarePlan />} />
            <Route path="/profile" element={<Profile />} />
            <Route path="/edit-profile" element={<EditProfile />} />
            <Route path="/skin-archive" element={<SkinArchive />} />
            <Route path="/pairing" element={<BluetoothPairing />} />
            <Route path="/tutorials" element={<Tutorials />} />
            <Route path="/tutorial/:id" element={<TutorialDetail />} />
            <Route path="/care-logs" element={<CareLogs />} />
            <Route path="/full-history" element={<FullHistory />} />
          </Routes>
        </main>

        <TabBar />
      </div>
    </Router>
  );
};

export default App;
